const input = $input.first().json;
const workflowId = String(input.workflow_id ?? '').trim();
const apiKey = String(input.api_key ?? '').trim();

if (!workflowId || workflowId.includes('REPLACE_WITH')) {
  throw new Error('workflow_id is required. Update the Config node.');
}

if (!apiKey || apiKey.includes('REPLACE_WITH')) {
  throw new Error('api_key is required. Update the Config node.');
}

const queueName = String(input.queue_name || 'default');
const tasksPerType = Math.max(1, Number(input.tasks_per_type || 1));
const minDelayMs = Math.floor(Math.max(0, Number(input.min_delay_ms || 0)));
const maxDelayMs = Math.floor(Math.max(minDelayMs, Number(input.max_delay_ms || minDelayMs)));
const runId = new Date().toISOString();

const taskTypes = [
  { kind: 'short', priority: 20, expectedDurationMs: 750 },
  { kind: 'medium', priority: 50, expectedDurationMs: 5000 },
  { kind: 'long', priority: 80, expectedDurationMs: 15000 }
];

const tasks = [];
for (const type of taskTypes) {
  for (let i = 1; i <= tasksPerType; i++) {
    tasks.push({
      workflow_id: workflowId,
      api_key: apiKey,
      queue_name: queueName,
      min_delay_ms: minDelayMs,
      max_delay_ms: maxDelayMs,
      run_id: runId,
      task_type: type.kind,
      task_name: `task_${type.kind}_${i}`,
      priority: type.priority,
      task_data: {
        workflow_id: workflowId,
        run_id: runId,
        task_type: type.kind,
        task_index: i,
        expected_duration_ms: type.expectedDurationMs,
        payload: {
          source: 'task-scheduler-random-enqueue-producer',
          schema_version: 1,
          note: 'consistent_task_data_shape'
        }
      }
    });
  }
}

for (let i = tasks.length - 1; i > 0; i--) {
  const j = Math.floor(Math.random() * (i + 1));
  [tasks[i], tasks[j]] = [tasks[j], tasks[i]];
}

const state = $getWorkflowStaticData('global');
state.current_run_id = runId;
state.dispatches = [];

return tasks.map((task, index) => ({
  json: {
    ...task,
    enqueue_order: index + 1,
    total_tasks: tasks.length
  }
}));

const item = $input.first().json;
const min = Math.floor(Math.max(0, Number(item.min_delay_ms || 0)));
const max = Math.floor(Math.max(min, Number(item.max_delay_ms || min)));
const delayMs = item.enqueue_order === 1 ? 0 : Math.floor(Math.random() * (max - min + 1)) + min;

if (delayMs > 0) {
  await new Promise(resolve => setTimeout(resolve, delayMs));
}

return [{
  json: {
    ...item,
    delay_ms: delayMs,
    delay_applied_at: new Date().toISOString()
  }
}];

const item = $input.first().json;

return [{
  json: {
    ...item,
    call: 'enqueue_task',
    args: {
      api_key: item.api_key,
      task_name: item.task_name,
      task_data: item.task_data,
      task_type: 'immediate',
      priority: item.priority,
      queue_name: item.queue_name
    }
  }
}];

const request = $('Build Enqueue Request').item.json;
const response = $input.first().json ?? {};
const taskUuid = response.enqueue_task || response.task_uuid || null;

const splitNode = $('Split Tasks');
const isLastItem = splitNode.context?.noItemsLeft === true;

const state = $getWorkflowStaticData('global');
if (!Array.isArray(state.dispatches) || state.current_run_id !== request.run_id) {
  state.current_run_id = request.run_id;
  state.dispatches = [];
}

state.dispatches.push({
  enqueue_order: request.enqueue_order,
  task_name: request.task_name,
  task_type: request.task_type,
  delay_ms: request.delay_ms,
  task_uuid: taskUuid,
  raw_response: response
});

return [{
  json: {
    ...request,
    task_uuid: taskUuid,
    is_last_item: isLastItem,
    dispatched_count: state.dispatches.length
  }
}];

const item = $input.first().json;
const state = $getWorkflowStaticData('global');
const dispatches = Array.isArray(state.dispatches) ? state.dispatches : [];
const successCount = dispatches.filter(d => typeof d.task_uuid === 'string' && d.task_uuid.length > 0).length;

return [{
  json: {
    run_id: item.run_id,
    workflow_id: item.workflow_id,
    queue_name: item.queue_name,
    total_tasks: dispatches.length,
    success_count: successCount,
    failed_count: dispatches.length - successCount,
    dispatches
  }
}];
